Test must fail on current code, pass on fixed code. Three attack vectors, three assertions.

Vector 1: bad signature still returns user → must become 401.
Vector 2: legacy X-User-Id alone → must become 401.
Vector 3: no auth at all → resolve_user returns None, endpoint must reject, not crash or grant.

```python
import pytest
from app.middleware.auth import AuthMiddleware, Unauthorized

class FakeRequest:
    def __init__(self, headers=None, cookies=None):
        self.headers = headers or {}
        self.cookies = cookies or {}

@pytest.fixture
def mw():
    m = AuthMiddleware()
    m.sessions = {}
    m._verify = lambda uid, sig: sig == f"valid-{uid}"
    return m

def test_bad_signature_rejected(mw):
    req = FakeRequest(headers={
        "X-Gateway-User-Id": "1",
        "X-Gateway-Signature": "forged",
    })
    with pytest.raises(Unauthorized):
        mw.resolve_user(req)

def test_missing_signature_rejected(mw):
    req = FakeRequest(headers={"X-Gateway-User-Id": "1"})
    with pytest.raises(Unauthorized):
        mw.resolve_user(req)

def test_legacy_x_user_id_rejected(mw):
    req = FakeRequest(headers={"X-User-Id": "1"})
    with pytest.raises(Unauthorized):
        mw.resolve_user(req)

def test_no_credentials_rejected(mw):
    req = FakeRequest()
    with pytest.raises(Unauthorized):
        mw.resolve_user(req)

def test_valid_signature_accepted(mw):
    req = FakeRequest(headers={
        "X-Gateway-User-Id": "42",
        "X-Gateway-Signature": "valid-42",
    })
    user = mw.resolve_user(req)
    assert user.id == "42"
```

Key property each test enforces: auth miss raises Unauthorized, never returns User or None. Last test is positive control — fix must not break happy path. Run against current diff: first four fail (return User or None instead of raising). Run against fixed middleware: all five pass.
